     1→// FreeLang v4 — Lexer (SPEC_04 구현)
     2→// UTF-8 소스코드 → 토큰 배열
     3→
     4→// ============================================================
     5→// TokenType — 6 카테고리, ~50종
     6→// ============================================================
     7→
     8→export enum TokenType {
     9→  // 키워드 (13)
    10→  VAR = "VAR",
    11→  LET = "LET",
    12→  CONST = "CONST",
    13→  FN = "FN",
    14→  IF = "IF",
    15→  ELSE = "ELSE",
    16→  MATCH = "MATCH",
    17→  FOR = "FOR",
    18→  IN = "IN",
    19→  RETURN = "RETURN",
    20→  SPAWN = "SPAWN",
    21→  TRUE = "TRUE",
    22→  FALSE = "FALSE",
    23→
    24→  // 타입 이름 (7)
    25→  TYPE_I32 = "TYPE_I32",
    26→  TYPE_I64 = "TYPE_I64",
    27→  TYPE_F64 = "TYPE_F64",
    28→  TYPE_BOOL = "TYPE_BOOL",
    29→  TYPE_STRING = "TYPE_STRING",
    30→  TYPE_VOID = "TYPE_VOID",
    31→  TYPE_CHANNEL = "TYPE_CHANNEL",
    32→
    33→  // 리터럴 (3)
    34→  INT_LIT = "INT_LIT",
    35→  FLOAT_LIT = "FLOAT_LIT",
    36→  STRING_LIT = "STRING_LIT",
    37→
    38→  // 연산자/구두점 (26)
    39→  PLUS = "PLUS",           // +
    40→  MINUS = "MINUS",         // -
    41→  STAR = "STAR",           // *
    42→  SLASH = "SLASH",         // /
    43→  PERCENT = "PERCENT",     // %
    44→  EQ = "EQ",               // =
    45→  EQEQ = "EQEQ",          // ==
    46→  NEQ = "NEQ",             // !=
    47→  LT = "LT",              // <
    48→  GT = "GT",               // >
    49→  LTEQ = "LTEQ",          // <=
    50→  GTEQ = "GTEQ",          // >=
    51→  AND = "AND",             // &&
    52→  OR = "OR",               // ||
    53→  NOT = "NOT",             // !
    54→  QUESTION = "QUESTION",   // ?
    55→  ARROW = "ARROW",         // =>
    56→  COLON = "COLON",         // :
    57→  COMMA = "COMMA",         // ,
    58→  DOT = "DOT",             // .
    59→  LPAREN = "LPAREN",       // (
    60→  RPAREN = "RPAREN",       // )
    61→  LBRACKET = "LBRACKET",   // [
    62→  RBRACKET = "RBRACKET",   // ]
    63→  LBRACE = "LBRACE",       // {
    64→  RBRACE = "RBRACE",       // }
    65→
    66→  // 특수 (2) — NEWLINE 토큰 없음 (SPEC_04 Q7)
    67→  IDENT = "IDENT",
    68→  EOF = "EOF",
    69→}
    70→
    71→// ============================================================
    72→// Token
    73→// ============================================================
    74→
    75→export type Token = {
    76→  type: TokenType;
    77→  lexeme: string;
    78→  line: number;
    79→  col: number;
    80→};
    81→
    82→// ============================================================
    83→// LexError
    84→// ============================================================
    85→
    86→export type LexError = {
    87→  message: string;
    88→  line: number;
    89→  col: number;
    90→};
    91→
    92→// ============================================================
    93→// 키워드 테이블 (SPEC_04 Q4)
    94→// ============================================================
    95→
    96→const KEYWORDS: Map<string, TokenType> = new Map([
    97→  // 키워드 (13)
    98→  ["var", TokenType.VAR],
    99→  ["let", TokenType.LET],
   100→  ["const", TokenType.CONST],
   101→  ["fn", TokenType.FN],
   102→  ["if", TokenType.IF],
   103→  ["else", TokenType.ELSE],
   104→  ["match", TokenType.MATCH],
   105→  ["for", TokenType.FOR],
   106→  ["in", TokenType.IN],
   107→  ["return", TokenType.RETURN],
   108→  ["spawn", TokenType.SPAWN],
   109→  ["true", TokenType.TRUE],
   110→  ["false", TokenType.FALSE],
   111→  // 타입 이름 (7)
   112→  ["i32", TokenType.TYPE_I32],
   113→  ["i64", TokenType.TYPE_I64],
   114→  ["f64", TokenType.TYPE_F64],
   115→  ["bool", TokenType.TYPE_BOOL],
   116→  ["string", TokenType.TYPE_STRING],
   117→  ["void", TokenType.TYPE_VOID],
   118→  ["channel", TokenType.TYPE_CHANNEL],
   119→]);
   120→
   121→// Option, Result, Ok, Err, Some, None은 키워드가 아님 → IDENT
   122→
   123→// ============================================================
   124→// Lexer
   125→// ============================================================
   126→
   127→export class Lexer {
   128→  private source: string;
   129→  private pos: number = 0;
   130→  private line: number = 1;
   131→  private col: number = 1;
   132→  private tokens: Token[] = [];
   133→  private errors: LexError[] = [];
   134→
   135→  constructor(source: string) {
   136→    this.source = source;
   137→  }
   138→
   139→  tokenize(): { tokens: Token[]; errors: LexError[] } {
   140→    while (!this.isAtEnd()) {
   141→      this.scanToken();
   142→    }
   143→    this.tokens.push({ type: TokenType.EOF, lexeme: "", line: this.line, col: this.col });
   144→    return { tokens: this.tokens, errors: this.errors };
   145→  }
   146→
   147→  private scanToken(): void {
   148→    const ch = this.peek();
   149→
   150→    // 공백 건너뜀 (스펙: ' ', '\t', '\r')
   151→    if (ch === " " || ch === "\t" || ch === "\r") {
   152→      this.advance();
   153→      return;
   154→    }
   155→
   156→    // 줄바꿈 — 토큰 생성 안 함, 줄 번호만 추적 (SPEC_04 Q7)
   157→    if (ch === "\n") {
   158→      this.advance();
   159→      this.line++;
   160→      this.col = 1;
   161→      return;
   162→    }
   163→
   164→    // 주석 또는 SLASH (SPEC_04 Q8)
   165→    if (ch === "/") {
   166→      if (this.peekNext() === "/") {
   167→        this.skipLineComment();
   168→        return;
   169→      }
   170→      if (this.peekNext() === "*") {
   171→        this.addError("block comments not supported, use //");
   172→        this.advance(); // /
   173→        this.advance(); // *
   174→        return;
   175→      }
   176→      this.addToken(TokenType.SLASH, "/");
   177→      this.advance();
   178→      return;
   179→    }
   180→
   181→    // 식별자 또는 키워드 (SPEC_04 Q4)
   182→    if (this.isAlpha(ch)) {
   183→      this.scanIdentOrKeyword();
   184→      return;
   185→    }
   186→
   187→    // 숫자 리터럴 (SPEC_04 Q5)
   188→    if (this.isDigit(ch)) {
   189→      this.scanNumber();
   190→      return;
   191→    }
   192→
   193→    // 문자열 리터럴 (SPEC_04 Q6)
   194→    if (ch === '"') {
   195→      this.scanString();
   196→      return;
   197→    }
   198→
   199→    // 2글자 연산자 먼저 확인 (최장 일치, SPEC_04 Q3)
   200→    const startLine = this.line;
   201→    const startCol = this.col;
   202→
   203→    if (ch === "=" && this.peekNext() === "=") {
   204→      this.advance(); this.advance();
   205→      this.tokens.push({ type: TokenType.EQEQ, lexeme: "==", line: startLine, col: startCol });
   206→      return;
   207→    }
   208→    if (ch === "=" && this.peekNext() === ">") {
   209→      this.advance(); this.advance();
   210→      this.tokens.push({ type: TokenType.ARROW, lexeme: "=>", line: startLine, col: startCol });
   211→      return;
   212→    }
   213→    if (ch === "!" && this.peekNext() === "=") {
   214→      this.advance(); this.advance();
   215→      this.tokens.push({ type: TokenType.NEQ, lexeme: "!=", line: startLine, col: startCol });
   216→      return;
   217→    }
   218→    if (ch === "<" && this.peekNext() === "=") {
   219→      this.advance(); this.advance();
   220→      this.tokens.push({ type: TokenType.LTEQ, lexeme: "<=", line: startLine, col: startCol });
   221→      return;
   222→    }
   223→    if (ch === ">" && this.peekNext() === "=") {
   224→      this.advance(); this.advance();
   225→      this.tokens.push({ type: TokenType.GTEQ, lexeme: ">=", line: startLine, col: startCol });
   226→      return;
   227→    }
   228→    if (ch === "&" && this.peekNext() === "&") {
   229→      this.advance(); this.advance();
   230→      this.tokens.push({ type: TokenType.AND, lexeme: "&&", line: startLine, col: startCol });
   231→      return;
   232→    }
   233→    if (ch === "|" && this.peekNext() === "|") {
   234→      this.advance(); this.advance();
   235→      this.tokens.push({ type: TokenType.OR, lexeme: "||", line: startLine, col: startCol });
   236→      return;
   237→    }
   238→
   239→    // 1글자 연산자/구두점
   240→    const singleCharTokens: Record<string, TokenType> = {
   241→      "+": TokenType.PLUS,
   242→      "-": TokenType.MINUS,
   243→      "*": TokenType.STAR,
   244→      "%": TokenType.PERCENT,
   245→      "=": TokenType.EQ,
   246→      "<": TokenType.LT,
   247→      ">": TokenType.GT,
   248→      "!": TokenType.NOT,
   249→      "?": TokenType.QUESTION,
   250→      ":": TokenType.COLON,
   251→      ",": TokenType.COMMA,
   252→      ".": TokenType.DOT,
   253→      "(": TokenType.LPAREN,
   254→      ")": TokenType.RPAREN,
   255→      "[": TokenType.LBRACKET,
   256→      "]": TokenType.RBRACKET,
   257→      "{": TokenType.LBRACE,
   258→      "}": TokenType.RBRACE,
   259→    };
   260→
   261→    const tokenType = singleCharTokens[ch];
   262→    if (tokenType !== undefined) {
   263→      this.addToken(tokenType, ch);
   264→      this.advance();
   265→      return;
   266→    }
   267→
   268→    // 알 수 없는 문자
   269→    this.addError(`unexpected character: ${ch}`);
   270→    this.advance();
   271→  }
   272→
   273→  // --------------------------------------------------------
   274→  // 식별자/키워드 스캔 (SPEC_04 Q4)
   275→  // --------------------------------------------------------
   276→
   277→  private scanIdentOrKeyword(): void {
   278→    const startCol = this.col;
   279→    const start = this.pos;
   280→
   281→    while (!this.isAtEnd() && this.isAlphaNum(this.peek())) {
   282→      this.advance();
   283→    }
   284→
   285→    const text = this.source.slice(start, this.pos);
   286→    const type = KEYWORDS.get(text) ?? TokenType.IDENT;
   287→    this.tokens.push({ type, lexeme: text, line: this.line, col: startCol });
   288→  }
   289→
   290→  // --------------------------------------------------------
   291→  // 숫자 스캔 (SPEC_04 Q5)
   292→  // --------------------------------------------------------
   293→
   294→  private scanNumber(): void {
   295→    const startCol = this.col;
   296→    const start = this.pos;
   297→    let isFloat = false;
   298→
   299→    // 정수부: [0-9][0-9_]*
   300→    this.consumeDigits();
   301→
   302→    // 소수점 확인: '.' 다음이 숫자면 FLOAT_LIT
   303→    if (!this.isAtEnd() && this.peek() === "." && this.isDigit(this.peekNext() ?? "")) {
   304→      isFloat = true;
   305→      this.advance(); // '.' 소비
   306→      this.consumeDigits();
   307→    }
   308→
   309→    const text = this.source.slice(start, this.pos);
   310→
   311→    // 밑줄 유효성 검사
   312→    if (text.endsWith("_")) {
   313→      this.errors.push({ message: "trailing underscore in number", line: this.line, col: startCol });
   314→      return;
   315→    }
   316→    if (text.includes("__")) {
   317→      this.errors.push({ message: "consecutive underscores in number", line: this.line, col: startCol });
   318→      return;
   319→    }
   320→
   321→    const type = isFloat ? TokenType.FLOAT_LIT : TokenType.INT_LIT;
   322→    this.tokens.push({ type, lexeme: text, line: this.line, col: startCol });
   323→  }
   324→
   325→  private consumeDigits(): void {
   326→    while (!this.isAtEnd() && (this.isDigit(this.peek()) || this.peek() === "_")) {
   327→      this.advance();
   328→    }
   329→  }
   330→
   331→  // --------------------------------------------------------
   332→  // 문자열 스캔 (SPEC_04 Q6)
   333→  // --------------------------------------------------------
   334→
   335→  private scanString(): void {
   336→    const startLine = this.line;
   337→    const startCol = this.col;
   338→    this.advance(); // 여는 '"' 소비
   339→
   340→    let value = "";
   341→
   342→    while (!this.isAtEnd() && this.peek() !== '"') {
   343→      const ch = this.peek();
   344→
   345→      // 줄바꿈 불허
   346→      if (ch === "\n") {
   347→        this.errors.push({
   348→          message: "newline in string literal, use \\n",
   349→          line: this.line,
   350→          col: this.col,
   351→        });
   352→        return;
   353→      }
   354→
   355→      // 이스케이프 시퀀스
   356→      if (ch === "\\") {
   357→        this.advance(); // '\' 소비
   358→        if (this.isAtEnd()) {
   359→          this.errors.push({ message: "unterminated string literal", line: startLine, col: startCol });
   360→          return;
   361→        }
   362→        const esc = this.peek();
   363→        switch (esc) {
   364→          case "n": value += "\n"; break;
   365→          case "t": value += "\t"; break;
   366→          case "r": value += "\r"; break;
   367→          case "\\": value += "\\"; break;
   368→          case '"': value += '"'; break;
   369→          case "0": value += "\0"; break;
   370→          default:
   371→            this.errors.push({
   372→              message: `unknown escape sequence: \\${esc}`,
   373→              line: this.line,
   374→              col: this.col - 1,
   375→            });
   376→            value += esc;
   377→        }
   378→        this.advance();
   379→        continue;
   380→      }
   381→
   382→      value += ch;
   383→      this.advance();
   384→    }
   385→
   386→    if (this.isAtEnd()) {
   387→      this.errors.push({ message: "unterminated string literal", line: startLine, col: startCol });
   388→      return;
   389→    }
   390→
   391→    this.advance(); // 닫는 '"' 소비
   392→
   393→    const lexeme = this.source.slice(this.source.indexOf('"', this.pos - value.length - 2 < 0 ? 0 : 0), this.pos);
   394→    this.tokens.push({ type: TokenType.STRING_LIT, lexeme: value, line: startLine, col: startCol });
   395→  }
   396→
   397→  // --------------------------------------------------------
   398→  // 주석 스캔 (SPEC_04 Q8)
   399→  // --------------------------------------------------------
   400→
   401→  private skipLineComment(): void {
   402→    this.advance(); // 첫 번째 '/'
   403→    this.advance(); // 두 번째 '/'
   404→    while (!this.isAtEnd() && this.peek() !== "\n") {
   405→      this.advance();
   406→    }
   407→    // '\n'은 소비하지 않음 — scanToken에서 줄 번호 처리
   408→  }
   409→
   410→  // --------------------------------------------------------
   411→  // 유틸리티
   412→  // --------------------------------------------------------
   413→
   414→  private isAtEnd(): boolean {
   415→    return this.pos >= this.source.length;
   416→  }
   417→
   418→  private peek(): string {
   419→    return this.source[this.pos];
   420→  }
   421→
   422→  private peekNext(): string | undefined {
   423→    return this.pos + 1 < this.source.length ? this.source[this.pos + 1] : undefined;
   424→  }
   425→
   426→  private advance(): void {
   427→    if (!this.isAtEnd()) {
   428→      this.pos++;
   429→      this.col++;
   430→    }
   431→  }
   432→
   433→  private isAlpha(ch: string): boolean {
   434→    return (ch >= "a" && ch <= "z") || (ch >= "A" && ch <= "Z") || ch === "_";
   435→  }
   436→
   437→  private isDigit(ch: string): boolean {
   438→    return ch >= "0" && ch <= "9";
   439→  }
   440→
   441→  private isAlphaNum(ch: string): boolean {
   442→    return this.isAlpha(ch) || this.isDigit(ch);
   443→  }
   444→
   445→  private addToken(type: TokenType, lexeme: string): void {
   446→    this.tokens.push({ type, lexeme, line: this.line, col: this.col });
   447→  }
   448→
   449→  private addError(message: string): void {
   450→    this.errors.push({ message, line: this.line, col: this.col });
   451→  }
   452→}
   453→

