     1→// FreeLang v4 — Parser (SPEC_05 구현)
     2→// RD(문) + Pratt(식) 하이브리드
     3→
     4→import { Token, TokenType } from "./lexer";
     5→import {
     6→  Program, Stmt, Expr, TypeAnnotation, Pattern, MatchArm, Param,
     7→} from "./ast";
     8→
     9→// ============================================================
    10→// ParseError
    11→// ============================================================
    12→
    13→export type ParseError = {
    14→  message: string;
    15→  line: number;
    16→  col: number;
    17→};
    18→
    19→// ============================================================
    20→// Binding Power (SPEC_05 Q4)
    21→// ============================================================
    22→
    23→const BP_ASSIGN = 10;
    24→const BP_OR = 20;
    25→const BP_AND = 30;
    26→const BP_EQUALITY = 40;
    27→const BP_COMPARISON = 50;
    28→const BP_ADDITIVE = 60;
    29→const BP_MULTIPLICATIVE = 70;
    30→const BP_UNARY = 90;
    31→const BP_POSTFIX = 100;
    32→
    33→function infixBP(type: TokenType): number {
    34→  switch (type) {
    35→    // EQ는 Pratt에서 처리하지 않음 → ExprStmt에서 할당으로 처리
    36→    case TokenType.OR: return BP_OR;
    37→    case TokenType.AND: return BP_AND;
    38→    case TokenType.EQEQ:
    39→    case TokenType.NEQ: return BP_EQUALITY;
    40→    case TokenType.LT:
    41→    case TokenType.GT:
    42→    case TokenType.LTEQ:
    43→    case TokenType.GTEQ: return BP_COMPARISON;
    44→    case TokenType.PLUS:
    45→    case TokenType.MINUS: return BP_ADDITIVE;
    46→    case TokenType.STAR:
    47→    case TokenType.SLASH:
    48→    case TokenType.PERCENT: return BP_MULTIPLICATIVE;
    49→    case TokenType.LPAREN:
    50→    case TokenType.LBRACKET:
    51→    case TokenType.DOT:
    52→    case TokenType.QUESTION: return BP_POSTFIX;
    53→    default: return 0;
    54→  }
    55→}
    56→
    57→// ============================================================
    58→// Parser
    59→// ============================================================
    60→
    61→export class Parser {
    62→  private tokens: Token[];
    63→  private pos: number = 0;
    64→  private errors: ParseError[] = [];
    65→
    66→  constructor(tokens: Token[]) {
    67→    this.tokens = tokens;
    68→  }
    69→
    70→  parse(): { program: Program; errors: ParseError[] } {
    71→    const stmts: Stmt[] = [];
    72→    while (!this.isAtEnd()) {
    73→      try {
    74→        stmts.push(this.parseStmt());
    75→      } catch (e) {
    76→        // 에러 복구: 다음 문 시작까지 건너뜀
    77→        this.synchronize();
    78→      }
    79→    }
    80→    return { program: { stmts }, errors: this.errors };
    81→  }
    82→
    83→  // ============================================================
    84→  // 문 파싱 — Recursive Descent (SPEC_05 Q1)
    85→  // ============================================================
    86→
    87→  private parseStmt(): Stmt {
    88→    const tok = this.peek();
    89→
    90→    switch (tok.type) {
    91→      case TokenType.VAR:
    92→      case TokenType.LET:
    93→      case TokenType.CONST:
    94→        return this.parseVarDecl();
    95→      case TokenType.FN:
    96→        return this.parseFnDecl();
    97→      case TokenType.IF:
    98→        return this.parseIfStmt();
    99→      case TokenType.MATCH:
   100→        return this.parseMatchStmt();
   101→      case TokenType.FOR:
   102→        return this.parseForStmt();
   103→      case TokenType.SPAWN:
   104→        return this.parseSpawnStmt();
   105→      case TokenType.RETURN:
   106→        return this.parseReturnStmt();
   107→      default:
   108→        return this.parseExprStmt();
   109→    }
   110→  }
   111→
   112→  // var/let/const 선언
   113→  private parseVarDecl(): Stmt {
   114→    const kw = this.advance(); // var/let/const
   115→    const mutable = kw.type === TokenType.VAR;
   116→    const name = this.expectIdent("variable name");
   117→    let type: TypeAnnotation | null = null;
   118→
   119→    if (this.check(TokenType.COLON)) {
   120→      this.advance(); // :
   121→      type = this.parseType();
   122→    }
   123→
   124→    this.expect(TokenType.EQ, "expected '=' in variable declaration");
   125→    const init = this.parseExpr(0);
   126→
   127→    return { kind: "var_decl", name, mutable, type, init, line: kw.line, col: kw.col };
   128→  }
   129→
   130→  // fn 선언
   131→  private parseFnDecl(): Stmt {
   132→    const kw = this.advance(); // fn
   133→    const name = this.expectIdent("function name");
   134→    this.expect(TokenType.LPAREN, "expected '(' after function name");
   135→
   136→    const params: Param[] = [];
   137→    if (!this.check(TokenType.RPAREN)) {
   138→      do {
   139→        const pName = this.expectIdent("parameter name");
   140→        this.expect(TokenType.COLON, "expected ':' after parameter name");
   141→        const pType = this.parseType();
   142→        params.push({ name: pName, type: pType });
   143→      } while (this.match(TokenType.COMMA));
   144→    }
   145→    this.expect(TokenType.RPAREN, "expected ')' after parameters");
   146→
   147→    // 반환 타입 (필수 — SPEC_06: 함수 시그니처 명시)
   148→    this.expect(TokenType.COLON, "expected ':' for return type");
   149→    const returnType = this.parseType();
   150→
   151→    this.expect(TokenType.LBRACE, "expected '{' for function body");
   152→    const body = this.parseBlock();
   153→
   154→    return { kind: "fn_decl", name, params, returnType, body, line: kw.line, col: kw.col };
   155→  }
   156→
   157→  // if 문 (문 위치)
   158→  private parseIfStmt(): Stmt {
   159→    const kw = this.advance(); // if
   160→    const condition = this.parseExpr(0);
   161→    this.expect(TokenType.LBRACE, "expected '{' after if condition");
   162→    const then = this.parseBlock();
   163→
   164→    let else_: Stmt[] | null = null;
   165→    if (this.match(TokenType.ELSE)) {
   166→      if (this.check(TokenType.IF)) {
   167→        // else if 체인
   168→        else_ = [this.parseIfStmt()];
   169→      } else {
   170→        this.expect(TokenType.LBRACE, "expected '{' after else");
   171→        else_ = this.parseBlock();
   172→      }
   173→    }
   174→
   175→    return { kind: "if_stmt", condition, then, else_, line: kw.line, col: kw.col };
   176→  }
   177→
   178→  // match 문
   179→  private parseMatchStmt(): Stmt {
   180→    const kw = this.advance(); // match
   181→    const subject = this.parseExpr(0);
   182→    this.expect(TokenType.LBRACE, "expected '{' after match expression");
   183→    const arms = this.parseMatchArms();
   184→    this.expect(TokenType.RBRACE, "expected '}' to close match");
   185→
   186→    return { kind: "match_stmt", subject, arms, line: kw.line, col: kw.col };
   187→  }
   188→
   189→  // for 문
   190→  private parseForStmt(): Stmt {
   191→    const kw = this.advance(); // for
   192→    const variable = this.expectIdent("loop variable");
   193→    this.expect(TokenType.IN, "expected 'in' after loop variable");
   194→    const iterable = this.parseExpr(0);
   195→    this.expect(TokenType.LBRACE, "expected '{' after for...in");
   196→    const body = this.parseBlock();
   197→
   198→    return { kind: "for_stmt", variable, iterable, body, line: kw.line, col: kw.col };
   199→  }
   200→
   201→  // spawn 문
   202→  private parseSpawnStmt(): Stmt {
   203→    const kw = this.advance(); // spawn
   204→    this.expect(TokenType.LBRACE, "expected '{' after spawn");
   205→    const body = this.parseBlock();
   206→
   207→    return { kind: "spawn_stmt", body, line: kw.line, col: kw.col };
   208→  }
   209→
   210→  // return 문
   211→  private parseReturnStmt(): Stmt {
   212→    const kw = this.advance(); // return
   213→
   214→    // return 뒤에 식이 있는지 확인
   215→    let value: Expr | null = null;
   216→    if (!this.check(TokenType.RBRACE) && !this.isAtEnd() && !this.isStmtStart()) {
   217→      value = this.parseExpr(0);
   218→    }
   219→
   220→    return { kind: "return_stmt", value, line: kw.line, col: kw.col };
   221→  }
   222→
   223→  // 식 문 (ExprStmt)
   224→  private parseExprStmt(): Stmt {
   225→    const tok = this.peek();
   226→    const expr = this.parseExpr(0);
   227→
   228→    // 할당 처리: expr = value
   229→    if (this.check(TokenType.EQ)) {
   230→      const eq = this.advance();
   231→      const value = this.parseExpr(0);
   232→      return {
   233→        kind: "expr_stmt",
   234→        expr: { kind: "assign", target: expr, value, line: eq.line, col: eq.col },
   235→        line: tok.line,
   236→        col: tok.col,
   237→      };
   238→    }
   239→
   240→    return { kind: "expr_stmt", expr, line: tok.line, col: tok.col };
   241→  }
   242→
   243→  // ============================================================
   244→  // 블록 파싱 ({ 이미 소비됨, } 소비함 )
   245→  // ============================================================
   246→
   247→  private parseBlock(): Stmt[] {
   248→    const stmts: Stmt[] = [];
   249→    while (!this.check(TokenType.RBRACE) && !this.isAtEnd()) {
   250→      try {
   251→        stmts.push(this.parseStmt());
   252→      } catch {
   253→        this.synchronize();
   254→      }
   255→    }
   256→    this.expect(TokenType.RBRACE, "expected '}'");
   257→    return stmts;
   258→  }
   259→
   260→  // ============================================================
   261→  // 식 파싱 — Pratt Parser (SPEC_05 Q3, Q4)
   262→  // ============================================================
   263→
   264→  private parseExpr(minBP: number): Expr {
   265→    let left = this.nud();
   266→
   267→    while (!this.isAtEnd()) {
   268→      const tok = this.peek();
   269→      const bp = infixBP(tok.type);
   270→      if (bp <= minBP) break;
   271→
   272→      left = this.led(left, bp);
   273→    }
   274→
   275→    return left;
   276→  }
   277→
   278→  // nud — prefix 위치
   279→  private nud(): Expr {
   280→    const tok = this.peek();
   281→
   282→    // 정수 리터럴
   283→    if (tok.type === TokenType.INT_LIT) {
   284→      this.advance();
   285→      const raw = tok.lexeme.replace(/_/g, "");
   286→      return { kind: "int_lit", value: parseInt(raw, 10), line: tok.line, col: tok.col };
   287→    }
   288→
   289→    // 부동소수점 리터럴
   290→    if (tok.type === TokenType.FLOAT_LIT) {
   291→      this.advance();
   292→      const raw = tok.lexeme.replace(/_/g, "");
   293→      return { kind: "float_lit", value: parseFloat(raw), line: tok.line, col: tok.col };
   294→    }
   295→
   296→    // 문자열 리터럴
   297→    if (tok.type === TokenType.STRING_LIT) {
   298→      this.advance();
   299→      return { kind: "string_lit", value: tok.lexeme, line: tok.line, col: tok.col };
   300→    }
   301→
   302→    // 불리언 리터럴
   303→    if (tok.type === TokenType.TRUE) {
   304→      this.advance();
   305→      return { kind: "bool_lit", value: true, line: tok.line, col: tok.col };
   306→    }
   307→    if (tok.type === TokenType.FALSE) {
   308→      this.advance();
   309→      return { kind: "bool_lit", value: false, line: tok.line, col: tok.col };
   310→    }
   311→
   312→    // 식별자 (channel도 식 위치에서는 함수 이름으로 사용)
   313→    if (tok.type === TokenType.IDENT || tok.type === TokenType.TYPE_CHANNEL) {
   314→      this.advance();
   315→      return { kind: "ident", name: tok.lexeme, line: tok.line, col: tok.col };
   316→    }
   317→
   318→    // 단항 연산자: - !
   319→    if (tok.type === TokenType.MINUS || tok.type === TokenType.NOT) {
   320→      this.advance();
   321→      const operand = this.parseExpr(BP_UNARY);
   322→      return { kind: "unary", op: tok.lexeme, operand, line: tok.line, col: tok.col };
   323→    }
   324→
   325→    // 괄호 그룹: ( expr )
   326→    if (tok.type === TokenType.LPAREN) {
   327→      this.advance();
   328→      const expr = this.parseExpr(0);
   329→      this.expect(TokenType.RPAREN, "expected ')'");
   330→      return expr;
   331→    }
   332→
   333→    // 배열 리터럴: [ elem, ... ]
   334→    if (tok.type === TokenType.LBRACKET) {
   335→      return this.parseArrayLit();
   336→    }
   337→
   338→    // 구조체 리터럴 (식 위치): { name: expr, ... }
   339→    if (tok.type === TokenType.LBRACE) {
   340→      return this.parseStructLit();
   341→    }
   342→
   343→    // if 식 (식 위치)
   344→    if (tok.type === TokenType.IF) {
   345→      return this.parseIfExpr();
   346→    }
   347→
   348→    // match 식 (식 위치)
   349→    if (tok.type === TokenType.MATCH) {
   350→      return this.parseMatchExpr();
   351→    }
   352→
   353→    this.error(`unexpected token: ${tok.lexeme}`, tok);
   354→    this.advance();
   355→    return { kind: "ident", name: "__error__", line: tok.line, col: tok.col };
   356→  }
   357→
   358→  // led — infix/postfix 위치
   359→  private led(left: Expr, bp: number): Expr {
   360→    const tok = this.peek();
   361→
   362→    // 이항 연산자
   363→    if (
   364→      tok.type === TokenType.PLUS || tok.type === TokenType.MINUS ||
   365→      tok.type === TokenType.STAR || tok.type === TokenType.SLASH ||
   366→      tok.type === TokenType.PERCENT ||
   367→      tok.type === TokenType.EQEQ || tok.type === TokenType.NEQ ||
   368→      tok.type === TokenType.LT || tok.type === TokenType.GT ||
   369→      tok.type === TokenType.LTEQ || tok.type === TokenType.GTEQ ||
   370→      tok.type === TokenType.AND || tok.type === TokenType.OR
   371→    ) {
   372→      this.advance();
   373→      const right = this.parseExpr(bp); // left-associative
   374→      return { kind: "binary", op: tok.lexeme, left, right, line: tok.line, col: tok.col };
   375→    }
   376→
   377→    // 함수 호출: expr(args)
   378→    if (tok.type === TokenType.LPAREN) {
   379→      this.advance();
   380→      const args: Expr[] = [];
   381→      if (!this.check(TokenType.RPAREN)) {
   382→        do {
   383→          args.push(this.parseExpr(0));
   384→        } while (this.match(TokenType.COMMA));
   385→      }
   386→      this.expect(TokenType.RPAREN, "expected ')' after arguments");
   387→      return { kind: "call", callee: left, args, line: tok.line, col: tok.col };
   388→    }
   389→
   390→    // 인덱스: expr[index]
   391→    if (tok.type === TokenType.LBRACKET) {
   392→      this.advance();
   393→      const index = this.parseExpr(0);
   394→      this.expect(TokenType.RBRACKET, "expected ']'");
   395→      return { kind: "index", object: left, index, line: tok.line, col: tok.col };
   396→    }
   397→
   398→    // 필드 접근: expr.field
   399→    if (tok.type === TokenType.DOT) {
   400→      this.advance();
   401→      const field = this.expectIdent("field name");
   402→      return { kind: "field_access", object: left, field, line: tok.line, col: tok.col };
   403→    }
   404→
   405→    // try 연산자: expr?
   406→    if (tok.type === TokenType.QUESTION) {
   407→      this.advance();
   408→      return { kind: "try", operand: left, line: tok.line, col: tok.col };
   409→    }
   410→
   411→    // 할당은 ExprStmt에서 처리하므로 여기선 패스
   412→    // EQ가 여기 오면 식 끝으로 처리
   413→    this.error(`unexpected operator: ${tok.lexeme}`, tok);
   414→    this.advance();
   415→    return left;
   416→  }
   417→
   418→  // ============================================================
   419→  // 복합 식 파싱
   420→  // ============================================================
   421→
   422→  // 배열 리터럴: [a, b, c]
   423→  private parseArrayLit(): Expr {
   424→    const tok = this.advance(); // [
   425→    const elements: Expr[] = [];
   426→    if (!this.check(TokenType.RBRACKET)) {
   427→      do {
   428→        elements.push(this.parseExpr(0));
   429→      } while (this.match(TokenType.COMMA));
   430→    }
   431→    this.expect(TokenType.RBRACKET, "expected ']'");
   432→    return { kind: "array_lit", elements, line: tok.line, col: tok.col };
   433→  }
   434→
   435→  // 구조체 리터럴: { name: expr, ... }
   436→  private parseStructLit(): Expr {
   437→    const tok = this.advance(); // {
   438→    const fields: { name: string; value: Expr }[] = [];
   439→    if (!this.check(TokenType.RBRACE)) {
   440→      do {
   441→        const name = this.expectIdent("field name");
   442→        this.expect(TokenType.COLON, "expected ':' after field name");
   443→        const value = this.parseExpr(0);
   444→        fields.push({ name, value });
   445→      } while (this.match(TokenType.COMMA));
   446→    }
   447→    this.expect(TokenType.RBRACE, "expected '}'");
   448→    return { kind: "struct_lit", fields, line: tok.line, col: tok.col };
   449→  }
   450→
   451→  // if 식 (식 위치, else 필수 — SPEC_06)
   452→  private parseIfExpr(): Expr {
   453→    const tok = this.advance(); // if
   454→    const condition = this.parseExpr(0);
   455→    this.expect(TokenType.LBRACE, "expected '{' after if condition");
   456→    const then = this.parseBlockExprs();
   457→    this.expect(TokenType.ELSE, "if expression requires else branch");
   458→    this.expect(TokenType.LBRACE, "expected '{' after else");
   459→    const else_ = this.parseBlockExprs();
   460→    return { kind: "if_expr", condition, then, else_, line: tok.line, col: tok.col };
   461→  }
   462→
   463→  // match 식 (식 위치)
   464→  private parseMatchExpr(): Expr {
   465→    const tok = this.advance(); // match
   466→    const subject = this.parseExpr(0);
   467→    this.expect(TokenType.LBRACE, "expected '{' after match expression");
   468→    const arms = this.parseMatchArms();
   469→    this.expect(TokenType.RBRACE, "expected '}' to close match");
   470→    return { kind: "match_expr", subject, arms, line: tok.line, col: tok.col };
   471→  }
   472→
   473→  // 블록 내 식 목록 (if/match 식의 body) → } 소비
   474→  private parseBlockExprs(): Expr[] {
   475→    const exprs: Expr[] = [];
   476→    while (!this.check(TokenType.RBRACE) && !this.isAtEnd()) {
   477→      exprs.push(this.parseExpr(0));
   478→    }
   479→    this.expect(TokenType.RBRACE, "expected '}'");
   480→    return exprs;
   481→  }
   482→
   483→  // ============================================================
   484→  // match arms
   485→  // ============================================================
   486→
   487→  private parseMatchArms(): MatchArm[] {
   488→    const arms: MatchArm[] = [];
   489→    while (!this.check(TokenType.RBRACE) && !this.isAtEnd()) {
   490→      const pattern = this.parsePattern();
   491→      this.expect(TokenType.ARROW, "expected '=>' after pattern");
   492→
   493→      let body: Expr;
   494→      if (this.check(TokenType.LBRACE)) {
   495→        // 블록 body
   496→        const bTok = this.advance(); // {
   497→        const stmts: Stmt[] = [];
   498→        while (!this.check(TokenType.RBRACE) && !this.isAtEnd()) {
   499→          stmts.push(this.parseStmt());
   500→        }
   501→        this.expect(TokenType.RBRACE, "expected '}'");
   502→        // 블록의 마지막 문이 ExprStmt면 그 식이 반환값
   503→        const lastExpr = stmts.length > 0 && stmts[stmts.length - 1].kind === "expr_stmt"
   504→          ? (stmts[stmts.length - 1] as any).expr
   505→          : null;
   506→        body = { kind: "block_expr", stmts: stmts.slice(0, lastExpr ? -1 : stmts.length), expr: lastExpr, line: bTok.line, col: bTok.col };
   507→      } else {
   508→        body = this.parseExpr(0);
   509→      }
   510→
   511→      this.match(TokenType.COMMA); // trailing comma optional
   512→      arms.push({ pattern, body });
   513→    }
   514→    return arms;
   515→  }
   516→
   517→  // ============================================================
   518→  // 패턴 파싱 (SPEC_05 Q8)
   519→  // ============================================================
   520→
   521→  private parsePattern(): Pattern {
   522→    const tok = this.peek();
   523→
   524→    // _ (wildcard)
   525→    if (tok.type === TokenType.IDENT && tok.lexeme === "_") {
   526→      this.advance();
   527→      return { kind: "wildcard" };
   528→    }
   529→
   530→    // Ok(p), Err(p), Some(p), None
   531→    if (tok.type === TokenType.IDENT) {
   532→      if (tok.lexeme === "Ok" || tok.lexeme === "Err" || tok.lexeme === "Some") {
   533→        this.advance();
   534→        this.expect(TokenType.LPAREN, `expected '(' after ${tok.lexeme}`);
   535→        const inner = this.parsePattern();
   536→        this.expect(TokenType.RPAREN, "expected ')'");
   537→        if (tok.lexeme === "Ok") return { kind: "ok", inner };
   538→        if (tok.lexeme === "Err") return { kind: "err", inner };
   539→        return { kind: "some", inner };
   540→      }
   541→      if (tok.lexeme === "None") {
   542→        this.advance();
   543→        return { kind: "none" };
   544→      }
   545→      // 일반 식별자 바인딩
   546→      this.advance();
   547→      return { kind: "ident", name: tok.lexeme };
   548→    }
   549→
   550→    // 리터럴 패턴
   551→    if (tok.type === TokenType.INT_LIT || tok.type === TokenType.FLOAT_LIT ||
   552→        tok.type === TokenType.STRING_LIT || tok.type === TokenType.TRUE ||
   553→        tok.type === TokenType.FALSE) {
   554→      const expr = this.nud();
   555→      return { kind: "literal", value: expr };
   556→    }
   557→
   558→    // 단항 마이너스 (음수 리터럴 패턴)
   559→    if (tok.type === TokenType.MINUS) {
   560→      const expr = this.nud(); // unary minus
   561→      return { kind: "literal", value: expr };
   562→    }
   563→
   564→    this.error("expected pattern", tok);
   565→    this.advance();
   566→    return { kind: "wildcard" };
   567→  }
   568→
   569→  // ============================================================
   570→  // 타입 파싱
   571→  // ============================================================
   572→
   573→  private parseType(): TypeAnnotation {
   574→    const tok = this.peek();
   575→
   576→    switch (tok.type) {
   577→      case TokenType.TYPE_I32: this.advance(); return { kind: "i32" };
   578→      case TokenType.TYPE_I64: this.advance(); return { kind: "i64" };
   579→      case TokenType.TYPE_F64: this.advance(); return { kind: "f64" };
   580→      case TokenType.TYPE_BOOL: this.advance(); return { kind: "bool" };
   581→      case TokenType.TYPE_STRING: this.advance(); return { kind: "string" };
   582→      case TokenType.TYPE_VOID: this.advance(); return { kind: "void" };
   583→      default:
   584→        break;
   585→    }
   586→
   587→    // [T] → 배열
   588→    if (tok.type === TokenType.LBRACKET) {
   589→      this.advance();
   590→      const element = this.parseType();
   591→      this.expect(TokenType.RBRACKET, "expected ']' for array type");
   592→      return { kind: "array", element };
   593→    }
   594→
   595→    // channel<T>
   596→    if (tok.type === TokenType.TYPE_CHANNEL) {
   597→      this.advance();
   598→      this.expect(TokenType.LT, "expected '<' after channel");
   599→      const element = this.parseType();
   600→      this.expect(TokenType.GT, "expected '>' for channel type");
   601→      return { kind: "channel", element };
   602→    }
   603→
   604→    // Option<T>
   605→    if (tok.type === TokenType.IDENT && tok.lexeme === "Option") {
   606→      this.advance();
   607→      this.expect(TokenType.LT, "expected '<' after Option");
   608→      const element = this.parseType();
   609→      this.expect(TokenType.GT, "expected '>' for Option type");
   610→      return { kind: "option", element };
   611→    }
   612→
   613→    // Result<T, E>
   614→    if (tok.type === TokenType.IDENT && tok.lexeme === "Result") {
   615→      this.advance();
   616→      this.expect(TokenType.LT, "expected '<' after Result");
   617→      const ok = this.parseType();
   618→      this.expect(TokenType.COMMA, "expected ',' in Result<T, E>");
   619→      const err = this.parseType();
   620→      this.expect(TokenType.GT, "expected '>' for Result type");
   621→      return { kind: "result", ok, err };
   622→    }
   623→
   624→    this.error(`expected type, got ${tok.lexeme}`, tok);
   625→    this.advance();
   626→    return { kind: "i32" }; // fallback
   627→  }
   628→
   629→  // ============================================================
   630→  // 유틸리티
   631→  // ============================================================
   632→
   633→  private peek(): Token {
   634→    return this.tokens[this.pos];
   635→  }
   636→
   637→  private advance(): Token {
   638→    const tok = this.tokens[this.pos];
   639→    if (!this.isAtEnd()) this.pos++;
   640→    return tok;
   641→  }
   642→
   643→  private check(type: TokenType): boolean {
   644→    return this.peek().type === type;
   645→  }
   646→
   647→  private match(type: TokenType): boolean {
   648→    if (this.check(type)) {
   649→      this.advance();
   650→      return true;
   651→    }
   652→    return false;
   653→  }
   654→
   655→  private expect(type: TokenType, message: string): Token {
   656→    if (this.check(type)) {
   657→      return this.advance();
   658→    }
   659→    const tok = this.peek();
   660→    this.error(`${message} (got ${tok.type}: "${tok.lexeme}")`, tok);
   661→    throw new Error(message);
   662→  }
   663→
   664→  private expectIdent(context: string): string {
   665→    const tok = this.peek();
   666→    if (tok.type === TokenType.IDENT) {
   667→      this.advance();
   668→      return tok.lexeme;
   669→    }
   670→    this.error(`expected ${context} (got ${tok.type}: "${tok.lexeme}")`, tok);
   671→    throw new Error(`expected ${context}`);
   672→  }
   673→
   674→  private isAtEnd(): boolean {
   675→    return this.peek().type === TokenType.EOF;
   676→  }
   677→
   678→  private isStmtStart(): boolean {
   679→    const t = this.peek().type;
   680→    return t === TokenType.VAR || t === TokenType.LET || t === TokenType.CONST ||
   681→           t === TokenType.FN || t === TokenType.IF || t === TokenType.MATCH ||
   682→           t === TokenType.FOR || t === TokenType.SPAWN || t === TokenType.RETURN;
   683→  }
   684→
   685→  private error(message: string, tok: Token): void {
   686→    this.errors.push({ message, line: tok.line, col: tok.col });
   687→  }
   688→
   689→  private synchronize(): void {
   690→    while (!this.isAtEnd()) {
   691→      if (this.isStmtStart()) return;
   692→      if (this.check(TokenType.RBRACE)) {
   693→        this.advance();
   694→        return;
   695→      }
   696→      this.advance();
   697→    }
   698→  }
   699→}
   700→

