    21→// ============================================================
    22→
    23→export type Pattern =
    24→  | { kind: "ident"; name: string }         // x → 바인딩
    25→  | { kind: "literal"; value: Expr }         // 42, "hello", true
    26→  | { kind: "ok"; inner: Pattern }           // Ok(v)
    27→  | { kind: "err"; inner: Pattern }          // Err(e)
