    36→
    37→// ============================================================
    38→// 식 (Expressions) — 값을 만든다
    39→// ============================================================
    40→
    41→export type Expr =
    42→  | { kind: "int_lit"; value: number; line: number; col: number }
    43→  | { kind: "float_lit"; value: number; line: number; col: number }
    44→  | { kind: "string_lit"; value: string; line: number; col: number }
    45→  | { kind: "bool_lit"; value: boolean; line: number; col: number }
    46→  | { kind: "ident"; name: string; line: number; col: number }
    47→  | { kind: "binary"; op: string; left: Expr; right: Expr; line: number; col: number }
    48→  | { kind: "unary"; op: string; operand: Expr; line: number; col: number }
    49→  | { kind: "call"; callee: Expr; args: Expr[]; line: number; col: number }
    50→  | { kind: "index"; object: Expr; index: Expr; line: number; col: number }
    51→  | { kind: "field_access"; object: Expr; field: string; line: number; col: number }
    52→  | { kind: "assign"; target: Expr; value: Expr; line: number; col: number }
    53→  | { kind: "try"; operand: Expr; line: number; col: number }
    54→  | { kind: "if_expr"; condition: Expr; then: Expr[]; else_: Expr[]; line: number; col: number }
    55→  | { kind: "match_expr"; subject: Expr; arms: MatchArm[]; line: number; col: number }
    56→  | { kind: "array_lit"; elements: Expr[]; line: number; col: number }
    57→  | { kind: "struct_lit"; fields: { name: string; value: Expr }[]; line: number; col: number }
    58→  | { kind: "block_expr"; stmts: Stmt[]; expr: Expr | null; line: number; col: number };
    59→
