    61→// 문 (Statements) — 값을 만들지 않는다
    62→// ============================================================
    63→
    64→export type Param = {
    65→  name: string;
    66→  type: TypeAnnotation;
    67→};
    68→
    69→export type Stmt =
    70→  | { kind: "var_decl"; name: string; mutable: boolean; type: TypeAnnotation | null; init: Expr; line: number; col: number }
    71→  | { kind: "fn_decl"; name: string; params: Param[]; returnType: TypeAnnotation; body: Stmt[]; line: number; col: number }
    72→  | { kind: "if_stmt"; condition: Expr; then: Stmt[]; else_: Stmt[] | null; line: number; col: number }
    73→  | { kind: "match_stmt"; subject: Expr; arms: MatchArm[]; line: number; col: number }
    74→  | { kind: "for_stmt"; variable: string; iterable: Expr; body: Stmt[]; line: number; col: number }
    75→  | { kind: "spawn_stmt"; body: Stmt[]; line: number; col: number }
    76→  | { kind: "return_stmt"; value: Expr | null; line: number; col: number }
    77→  | { kind: "expr_stmt"; expr: Expr; line: number; col: number };
    78→
    79→// ============================================================
    80→// 프로그램 (최상위)
    81→// ============================================================
    82→
    83→export type Program = {
    84→  stmts: Stmt[];
    85→};
