    56→// 스코프 (SPEC_08: 3종 — global, function, block)
    57→// ============================================================
    58→
    59→class Scope {
    60→  vars: Map<string, VarInfo> = new Map();
    61→  parent: Scope | null;
    62→
    63→  constructor(parent: Scope | null) {
    64→    this.parent = parent;
    65→  }
    66→
    67→  define(name: string, info: VarInfo): void {
    68→    this.vars.set(name, info);
    69→  }
    70→
    71→  lookup(name: string): VarInfo | null {
    72→    const v = this.vars.get(name);
    73→    if (v) return v;
    74→    if (this.parent) return this.parent.lookup(name);
    75→    return null;
    76→  }
    77→}
